const CREDIT_VALUE_EUR = 0.10;
// Legacy flat revenue — use getModelRevenue(type, model) for accurate per-model tracking
const REVENUE_PER_TYPE: Record<string, number> = {
  text: 2 * CREDIT_VALUE_EUR, image: 5 * CREDIT_VALUE_EUR,
  video: 30 * CREDIT_VALUE_EUR, audio: 5 * CREDIT_VALUE_EUR,
};
const USD_TO_EUR = 0.92;

interface CostEntry {
  id: string; timestamp: string; type: "text" | "image" | "video" | "audio";
  model: string; provider: string; costUsd: number; costEur: number;
  revenueEur: number; marginEur: number; latencyMs: number; userId: string; success: boolean;
}

async function logCost(entry: Omit<CostEntry, "id" | "timestamp" | "costEur" | "marginEur">) {
  try {
    const costEur = entry.costUsd * USD_TO_EUR;
    const marginEur = entry.revenueEur - costEur;
    const id = `cost:${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    const full: CostEntry = { ...entry, id, timestamp: new Date().toISOString(),
      costEur: Math.round(costEur * 10000) / 10000, marginEur: Math.round(marginEur * 10000) / 10000 };
    await kv.set(id, full);
    console.log(`[cost] ${entry.type}/${entry.provider}: cost=$${entry.costUsd} rev=EUR${entry.revenueEur} margin=EUR${full.marginEur}`);
  } catch (e) { console.log("[logCost] failed:", e); }
}

function getProviderCost(provider: string, type: string): number {
  if (PROVIDER_COSTS[provider]) return PROVIDER_COSTS[provider];
  const prefix = provider.split("/")[0];
  if (prefix === "luma") return type === "video" ? 0.150 : 0.030;
  if (prefix === "replicate") return type === "audio" ? 0.050 : 0.005;
  if (prefix === "apipod") return 0.015;
  return 0.010;
}

// ══════════════════════════════════════════════════════════════
// INLINE AI — TEXT (APIPod), IMAGE (Luma Photon), VIDEO (Luma Ray), AUDIO (Replicate)
// ══════════════════════════════════════════════════════════════

const APIPOD_BASE = "https://api.apipod.ai/v1";
const LUMA_BASE = "https://api.lumalabs.ai/dream-machine/v1";
const HIGGSFIELD_BASE = "https://platform.higgsfield.ai";
const LEONARDO_BASE = "https://cloud.leonardo.ai/api/rest/v1";
const LEONARDO_V2_BASE = "https://cloud.leonardo.ai/api/rest/v2";
const TOGETHER_BASE = "https://api.together.xyz/v1";

// ══════════════════════════════════════════════════════════════
// TOGETHER AI — Open-source models (Llama, DeepSeek, Qwen, Kimi, GLM, Flux)
// OpenAI-compatible API. Costs 5-30× less than proprietary providers.
// ══════════════════════════════════════════════════════════════

// Map ORA model IDs → Together API model slugs + metadata
// Pricing in EUR per 1M tokens (text) or per image (images)
const TOGETHER_MODELS: Record<string, {
  apiModel: string;
  type: "text" | "image";
  pricePerMTokens?: number; // EUR per 1M output tokens (approximate)
  pricePerImage?: number;   // EUR per image
  capabilities?: string[];
}> = {
  // ── Text models ──
  "together-llama-3.3-70b": { apiModel: "meta-llama/Llama-3.3-70B-Instruct-Turbo", type: "text", pricePerMTokens: 0.80, capabilities: ["general", "multilingual", "fast"] },
  "together-deepseek-v3":   { apiModel: "deepseek-ai/DeepSeek-V3", type: "text", pricePerMTokens: 1.10, capabilities: ["reasoning", "code", "fast"] },
  "together-deepseek-r1":   { apiModel: "deepseek-ai/DeepSeek-R1", type: "text", pricePerMTokens: 6.50, capabilities: ["reasoning", "deep-think"] },
  "together-qwen-2.5-72b":  { apiModel: "Qwen/Qwen2.5-72B-Instruct-Turbo", type: "text", pricePerMTokens: 1.10, capabilities: ["multilingual", "french", "creative"] },
  "together-kimi-k2":       { apiModel: "moonshotai/Kimi-K2-Instruct", type: "text", pricePerMTokens: 2.20, capabilities: ["long-context", "reasoning"] },
  "together-glm-4.5":       { apiModel: "zai-org/GLM-4.5", type: "text", pricePerMTokens: 1.80, capabilities: ["creative", "copywriting"] },
  "together-gpt-oss-120b":  { apiModel: "openai/gpt-oss-120b", type: "text", pricePerMTokens: 1.40, capabilities: ["general", "open-weights"] },

  // ── Image models ──
  "together-flux-schnell":  { apiModel: "black-forest-labs/FLUX.1-schnell", type: "image", pricePerImage: 0.003, capabilities: ["ultra-fast", "draft"] },
  "together-flux-dev":      { apiModel: "black-forest-labs/FLUX.1-dev", type: "image", pricePerImage: 0.025, capabilities: ["quality", "balanced"] },
  "together-flux-pro-1.1":  { apiModel: "black-forest-labs/FLUX.1.1-pro", type: "image", pricePerImage: 0.040, capabilities: ["premium", "photorealism"] },
};

function togetherHeaders(): Record<string, string> {
  const key = Deno.env.get("TOGETHER_API_KEY") || "";
  return { "Content-Type": "application/json", Authorization: `Bearer ${key}` };
}

// Call Together AI for text generation (OpenAI-compatible)
async function callTogetherText(
  oraModelId: string,
  messages: { role: string; content: string }[],
  opts: { maxTokens?: number; temperature?: number; timeoutMs?: number } = {}
): Promise<{ text: string; apiModel: string; latencyMs: number }> {
  const t0 = Date.now();
  const key = Deno.env.get("TOGETHER_API_KEY");
  if (!key) throw new Error("TOGETHER_API_KEY not set");
  const entry = TOGETHER_MODELS[oraModelId];
  if (!entry || entry.type !== "text") throw new Error(`Unknown Together text model: ${oraModelId}`);

  const res = await fetch(`${TOGETHER_BASE}/chat/completions`, {
    method: "POST",
    headers: togetherHeaders(),
    body: JSON.stringify({
      model: entry.apiModel,
      messages,
      max_tokens: opts.maxTokens || 4096,
      temperature: opts.temperature ?? 0.7,
    }),
    signal: AbortSignal.timeout(opts.timeoutMs || 60_000),
  });
  if (!res.ok) {
    const body = await res.text();
    throw new Error(`Together ${res.status}: ${body.slice(0, 300)}`);
  }
  const data = await res.json();
  const text = data.choices?.[0]?.message?.content || "";
  return { text, apiModel: entry.apiModel, latencyMs: Date.now() - t0 };
}

// Call Together AI for image generation
// Supports both response formats (url, b64_json) and falls back to the Free
// variant of FLUX.1-schnell if the paid model returns an auth/billing error.
async function callTogetherImage(
  oraModelId: string,
  prompt: string,
  opts: { width?: number; height?: number; steps?: number; timeoutMs?: number } = {}
): Promise<{ imageUrl: string; apiModel: string; latencyMs: number }> {
  const t0 = Date.now();
  const key = Deno.env.get("TOGETHER_API_KEY");
  if (!key) throw new Error("TOGETHER_API_KEY not set");
  const entry = TOGETHER_MODELS[oraModelId];
  if (!entry || entry.type !== "image") throw new Error(`Unknown Together image model: ${oraModelId}`);

  // Flux schnell: 4 steps max. Flux dev/pro: up to 28 steps.
  const steps = opts.steps ?? (oraModelId === "together-flux-schnell" ? 4 : 28);

  const attempt = async (apiModel: string) => {
    const res = await fetch(`${TOGETHER_BASE}/images/generations`, {
      method: "POST",
      headers: togetherHeaders(),
      body: JSON.stringify({
        model: apiModel,
        prompt: prompt.slice(0, 2000),
        width: opts.width || 1024,
        height: opts.height || 1024,
        steps,
        n: 1,
      }),
      signal: AbortSignal.timeout(opts.timeoutMs || 60_000),
    });
    const bodyText = await res.text();
    if (!res.ok) {
      const err = new Error(`Together image ${res.status}: ${bodyText.slice(0, 300)}`);
      (err as any).status = res.status;
      throw err;
    }
    let data: any;
    try { data = JSON.parse(bodyText); } catch { throw new Error(`Together image: invalid JSON response`); }
    const first = data.data?.[0] || {};
    // Together returns either { url } or { b64_json } depending on model / server choice
    if (first.url) return first.url as string;
    if (first.b64_json) return `data:image/png;base64,${first.b64_json}`;
    throw new Error("Together returned no image data");
  };

  try {
    const imageUrl = await attempt(entry.apiModel);
    return { imageUrl, apiModel: entry.apiModel, latencyMs: Date.now() - t0 };
  } catch (err: any) {
    // Fallback: FLUX.1-schnell has a free tier variant that works without paid billing
    const status = err?.status;
    if (oraModelId === "together-flux-schnell" && (status === 402 || status === 403 || status === 404)) {
      console.log(`[together-image] ${entry.apiModel} failed ${status}, trying free variant`);
      const imageUrl = await attempt("black-forest-labs/FLUX.1-schnell-Free");
      return { imageUrl, apiModel: "black-forest-labs/FLUX.1-schnell-Free", latencyMs: Date.now() - t0 };
    }
    throw err;
  }
}

// Helper: is this an ORA model ID routed to Together?
function isTogetherModel(oraModelId: string): boolean {
  return oraModelId.startsWith("together-") && !!TOGETHER_MODELS[oraModelId];
}

// Raw Together call using an arbitrary API model slug (e.g. a fine-tuned model)
async function callTogetherTextRaw(
  apiModel: string,
  messages: { role: string; content: string }[],
  opts: { maxTokens?: number; temperature?: number; timeoutMs?: number } = {}
): Promise<{ text: string; apiModel: string; latencyMs: number }> {
  const t0 = Date.now();
  const key = Deno.env.get("TOGETHER_API_KEY");
  if (!key) throw new Error("TOGETHER_API_KEY not set");
  const res = await fetch(`${TOGETHER_BASE}/chat/completions`, {
    method: "POST",
    headers: togetherHeaders(),
    body: JSON.stringify({
      model: apiModel,
      messages,
      max_tokens: opts.maxTokens || 4096,
      temperature: opts.temperature ?? 0.7,
    }),
    signal: AbortSignal.timeout(opts.timeoutMs || 60_000),
  });
  if (!res.ok) {
    const body = await res.text();
    throw new Error(`Together ${res.status}: ${body.slice(0, 300)}`);
  }
  const data = await res.json();
  const text = data.choices?.[0]?.message?.content || "";
  return { text, apiModel, latencyMs: Date.now() - t0 };
}

// ── SMART ROUTER ──
// Picks the cheapest Together text model capable of the task.
// Used when no explicit model is requested, to save 90%+ on inference costs
// silently compared to routing everything through GPT-4o.
type RoutingNeed = "simple" | "reasoning" | "long-context" | "multilingual" | "creative";

function pickCheapestTogetherText(need: RoutingNeed): string | null {
  if (!Deno.env.get("TOGETHER_API_KEY")) return null;
  // Map need → preferred model (cheapest that fits the job)
  const routes: Record<RoutingNeed, string> = {
    "simple":        "together-llama-3.3-70b", // €0.0008/run — default for social posts
    "reasoning":     "together-deepseek-v3",   // €0.0011/run — general reasoning, fast
    "long-context":  "together-kimi-k2",       // €0.0022/run — 2M tokens
    "multilingual":  "together-qwen-2.5-72b",  // €0.0011/run — strong FR/multilingual
    "creative":      "together-glm-4.5",       // €0.0018/run — copywriting
  };
  return routes[need];
}

// Infer routing need from brief + format characteristics
function inferRoutingNeed(brief: string, formatIds: string[], lang: string): RoutingNeed {
  const hasLongForm = formatIds.some(id =>
    id === "blog-article" || id === "linkedin-article" || id === "newsletter" || id === "press-release"
  );
  const isFrench = lang === "fr";
  const briefLen = brief.length;
  const hasStrategicKeywords = /\b(strategy|strategie|positionnement|complex|concurrent|analysis|analyse|roadmap)\b/i.test(brief);

  if (hasStrategicKeywords) return "reasoning";
  if (hasLongForm && briefLen > 1000) return "long-context";
  if (hasLongForm) return "creative";
  if (isFrench) return "multilingual";
  return "simple";
}

// ── PROMPT ENHANCER — translates any language to English + produces cinematic photorealistic prompts ──
async function enhanceImagePrompt(rawPrompt: string, preserveBrandName: boolean = false, brandCtx?: BrandContext | null): Promise<string> {
  const t0 = Date.now();
  const key = Deno.env.get("APIPOD_API_KEY");
  if (!key) { console.log("[enhancePrompt] No API key, using raw"); return rawPrompt; }
  const enhanceModels = ["gpt-4o", "gpt-5"];
  const isVague = rawPrompt.trim().split(/\s+/).length < 20;

  // ── ARTISTIC STYLE DETECTION — bypass photo-realism when user requests a painting style ──
  const artisticPatterns = /\b(style\s+(of|de|du|d')\s*|à la (manière|façon)\s+(de|du|d')\s*|in the style of\s*|inspired by\s*|comme\s+|like\s+)(monet|van\s*gogh|picasso|basquiat|klimt|warhol|hokusai|dali|matisse|kandinsky|mondrian|rembrandt|vermeer|caravage|caravaggio|turner|cézanne|cezanne|renoir|degas|gauguin|munch|rothko|pollock|banksy|frida\s*kahlo|kahlo|magritte|hockney|lichtenstein|seurat|chagall|klee|miró|miro|schiele|bacon|haring|keith\s*haring|botticelli|raphael|raphaël|michelangelo|michel-ange|léonard\s*de\s*vinci|da\s*vinci|toulouse-lautrec|impressionnist|impressionist|cubis[mt]|surrealis[mt]|expressionnis[mt]|pop\s*art|art\s*nouveau|art\s*deco|fauvism|fauvis[mt]|renaissance|baroque|pointillis[mt]|abstract\s*expressionism)/i;
  const isArtistic = artisticPatterns.test(rawPrompt);

  // Build brand direction block — injected into system prompt so the AI composes a unified creative vision
  let brandDirectionBlock = "";
  if (brandCtx) {
    const bd: string[] = [];
    const allColors = [...new Set([...brandCtx.colorPalette, ...brandCtx.imageBankColors])].slice(0, 6);
    if (allColors.length > 0) bd.push(`Color palette: ${brandCtx.colorNames.length > 0 ? brandCtx.colorNames.join(", ") : allColors.join(", ")}. Weave these colors into the scene through props, wardrobe, background elements, or light tint — never as flat color blocks.`);
    if (brandCtx.photoStyle) {
      if (brandCtx.photoStyle.mood) bd.push(`Mood: ${brandCtx.photoStyle.mood}`);
      if (brandCtx.photoStyle.lighting) bd.push(`Lighting direction: ${brandCtx.photoStyle.lighting}`);
      if (brandCtx.photoStyle.framing) bd.push(`Framing: ${brandCtx.photoStyle.framing}`);
      if (brandCtx.photoStyle.subjects) bd.push(`Subject treatment: ${brandCtx.photoStyle.subjects}`);
    }
    if (brandCtx.imageBankMoods.length > 0) bd.push(`Emotional territory (from brand reference photos): ${brandCtx.imageBankMoods.slice(0, 4).join(", ")}`);
    if (brandCtx.imageBankStyles.length > 0) bd.push(`Visual style references: ${brandCtx.imageBankStyles.slice(0, 3).join(", ")}`);
    if (brandCtx.imageBankLighting.length > 0) bd.push(`Lighting patterns: ${brandCtx.imageBankLighting.slice(0, 3).join(", ")}`);
    if (brandCtx.imageBankCompositions.length > 0) bd.push(`Composition patterns: ${brandCtx.imageBankCompositions.slice(0, 3).join(", ")}`);
    if (brandCtx.industry) bd.push(`Industry: ${brandCtx.industry}`);
    if (bd.length > 0) {
      brandDirectionBlock = `\n\nBRAND CREATIVE DIRECTION (MANDATORY — this defines the visual identity of the output):
${bd.join("\n")}

YOUR JOB: Compose a SINGLE unified prompt where the brand direction is woven INTO the scene description — not appended as keywords. The lighting, color grading, props, wardrobe, and atmosphere should all serve the brand's visual identity. Think like an art director briefing a photographer: "I want the viewer to feel X, using Y light, with Z color accents."`;
    }
  }

  // ── ARTISTIC MODE — completely different system prompt for painting/art styles ──
  if (isArtistic) {
    console.log(`[enhancePrompt] ARTISTIC MODE detected for: "${rawPrompt.slice(0, 60)}"`);
    const artisticSystemPrompt = `You are a world-class art director specializing in fine art reproduction and style transfer. Your ONLY job: transform the user's request into a single, detailed English prompt that will generate an image faithfully reproducing the ARTISTIC STYLE of the referenced painter or movement.

CRITICAL RULES:
1. PRESERVE THE ARTIST/STYLE — The named painter or art movement is the #1 priority. Every visual choice must serve that style.
2. STUDY THE MASTER — For each artist, invoke their SIGNATURE techniques:
   - Monet: loose impressionist brushstrokes, dappled light, soft edges, plein-air feel, pastel color harmonics
   - Van Gogh: thick impasto swirls, bold expressive color, visible heavy brushwork, emotional intensity, starry/turbulent energy
   - Picasso: cubist fragmentation, multiple perspectives simultaneously, geometric forms, bold outlines, muted earth + blue/rose
   - Basquiat: raw neo-expressionist marks, graffiti-like text fragments, crown motifs, chaotic layering, primal energy
   - Klimt: golden decorative patterns, Art Nouveau ornament, mosaic-like flat areas mixed with realistic faces, sensual
   - Warhol: pop art flat colors, screen-print aesthetic, repetition, bold outlines, commercial/ironic
   - Hokusai: ukiyo-e woodblock style, precise linework, flat color planes, waves/nature, Japanese composition
   - Dalí: surrealist melting forms, hyper-detailed dreamscapes, impossible physics, desert landscapes
   - Matisse: bold fauve colors, simplified organic shapes, joyful flat patterns, decorative
   - Rembrandt: dramatic chiaroscuro, rich dark palette, luminous skin, theatrical lighting
   - Renaissance: balanced composition, sfumato, idealized forms, classical perspective, religious grandeur
   - Impressionism: broken color, visible brushwork, light effects, outdoor scenes, fleeting moments
   - Cubism: fragmented forms, multiple viewpoints, geometric planes, muted palette
   - Expressionism: distorted forms, intense emotion, bold non-naturalistic color
   - Pop Art: commercial imagery, flat bold color, screen-print dots, irony
3. DESCRIBE AS A PAINTING — Use terms like "oil on canvas", "watercolor", "brushstrokes visible", "painted in the style of". NEVER use photography terms (no camera, no lens, no film stock).
4. PRESERVE THE SUBJECT — Keep the user's subject matter (the scene, objects, people they described) but render it through the artist's visual language.
5. OUTPUT ONLY the prompt text. No quotes, no explanation. 80-150 words.
6. If the user's request is in another language, translate faithfully to English.
7. End with: "No text, no watermarks, no AI artifacts. Fine art painting, museum quality, high resolution."`;

    for (const m of enhanceModels) {
      try {
        const res = await fetch(`${APIPOD_BASE}/chat/completions`, {
          method: "POST",
          headers: { "Content-Type": "application/json", Authorization: `Bearer ${key}` },
          body: JSON.stringify({
            model: m,
            messages: [
              { role: "system", content: artisticSystemPrompt },
              { role: "user", content: rawPrompt },
            ],
            max_tokens: 400,
          }),
          signal: AbortSignal.timeout(12_000),
        });
        if (!res.ok) { console.log(`[enhancePrompt/artistic] ${m} returned ${res.status}, trying next...`); continue; }
        const data = await res.json();
        const enhanced = data.choices?.[0]?.message?.content?.trim();
        if (enhanced && enhanced.length > 20) {
          console.log(`[enhancePrompt/artistic] OK via ${m} (${Date.now() - t0}ms): "${rawPrompt.slice(0, 40)}" → "${enhanced.slice(0, 120)}"`);
          return enhanced;
        }
      } catch (err) { console.log(`[enhancePrompt/artistic] ${m} error: ${err}`); }
    }
    return rawPrompt;
  }

  const systemPrompt = `You are a world-class image prompt engineer — trained at Magnum Photos, Tyler Mitchell's studio, and Stink Studios. You create images that look like they were shot TODAY by a top-tier photographer for Vogue, Kinfolk, or Apple. Your ONLY job: transform the user's request into a single, hyper-detailed English prompt that produces AUTHENTIC, MODERN, ANTI-STOCK images.
${brandDirectionBlock}
THE #1 RULE — ANTI-STOCK AESTHETIC:
Stock photos are DEAD. They look fake because: perfect lighting, sterile environments, forced smiles, generic "business" setups, overly clean compositions, people doing nothing real.
YOUR images must feel CANDID, REAL, ALIVE:
- Imperfect beauty: a hair out of place, a crease in the shirt, a half-finished coffee, condensation on a glass
- Real moments: mid-gesture, mid-laugh, looking away from camera, caught in thought
- Textured environments: lived-in spaces, worn surfaces, real weather, natural mess
- Modern color grading: desaturated earth tones, or bold monochrome with one accent, or warm film grain — NEVER the "bright airy stock" look (blown-out whites + saturated primaries)
- SKIN & PEOPLE: Real skin texture — pores, freckles, fine lines, uneven tone. NEVER smooth/airbrushed/plastic skin. No uncanny valley. Natural body proportions. Real hair texture, not salon-perfect. Hands with veins, knuckles, imperfect nails. Eyes with actual catchlights and natural asymmetry.
- AVOID AT ALL COSTS: people pointing at laptops, handshakes, arms crossed, thumbs up, sterile white offices, generic coffee shops with identical chairs, "diverse group smiling at camera", airbrushed skin, plastic-looking faces, perfect symmetry, over-saturated colors

METHODOLOGY — SCENE-STACK (build every prompt in this order):
1. SUBJECT — What is the hero element? Describe with material precision: texture, wear, patina, surface finish, micro-details.
2. CAMERA — Specific body + lens. Examples: "Sony A7IV, Sigma 35mm f/1.4 Art wide open", "Fujifilm X-T5, 56mm f/1.2", "Leica Q3, 28mm". ALWAYS specify a WIDE aperture (f/1.2-f/2.8) for natural depth of field.
3. ENVIRONMENT — Where? Be HYPER-SPECIFIC: not "a café" but "a corner table at a Parisian zinc-top bar, afternoon light cutting through half-closed wooden shutters, espresso cup with lipstick trace". Include sensory details: steam, dust particles, reflections.
4. MOMENT — What JUST happened or is about to happen? A frozen micro-story. Not posed — captured.
5. EMOTION — What should the viewer FEEL? Be specific: not "warmth" but "the quiet intimacy of a Sunday morning before anyone else wakes up".
6. LIGHT — Choose ONE precise lighting setup:
   - Golden Hour Side-Light: warm directional, long shadows, amber skin tones — for lifestyle
   - Overcast Window Light: soft, directional, flattering — for interiors, portraits
   - Backlit Haze: subject edge-lit, face in gentle shadow, lens flare — for atmosphere
   - Neon/Practical Mixed: colored ambient from real sources — for urban, nightlife
   - Hard Midday Sun: high contrast, sharp shadows, bleached highlights — for editorial, summer
   - Chiaroscuro: extreme contrast, velvet blacks — for luxury, dramatic
7. FILM LOOK — Color grading direction: "Kodak Portra 400 tones" or "Fuji Pro 400H greens" or "bleach bypass desaturated" or "cross-processed warm" or "Cinestill 800T tungsten shift". NEVER say "vibrant and colorful".
8. ANTI-DEFECTS — End with: "No text, no logos, no watermarks, no AI artifacts. Shot on film, 8K scan."

${isVague ? `SHORT/VAGUE PROMPT DETECTED — EXPANSION PROTOCOL:
The user wrote a brief request. You MUST expand it into a SPECIFIC, CINEMATIC scene.
1. IDENTIFY the core subject
2. INVENT a hyper-specific context — not generic, but a precise MOMENT in a precise PLACE
3. ADD the "decisive moment" — something happening that makes the image feel alive
4. CHOOSE a strong film/color look that fits the mood
5. DEFAULT TO EDITORIAL REALISM — it should look like a candid shot from a documentary or fashion editorial, not an ad

Example: "coffee shop" → "A woman in her 30s, dark wool coat slightly open, sits alone at a weathered marble counter in a narrow Milanese espresso bar. She holds a small ceramic cup with both hands, steam curling upward, eyes closed in a micro-moment of morning stillness. Behind her, blurred regulars stand at the bar. Shot on Fujifilm X-T5, 56mm f/1.2 wide open, shallow depth of field isolating her face. Overcast winter light from a tall window camera-left. Muted earth tones, Kodak Portra 400 color palette, slight film grain. No text, no logos, no watermarks, no AI artifacts. Shot on film, 8K scan."

NEVER ask for clarification. NEVER output multiple options. Pick the BEST interpretation and commit fully.
` : ''}OUTPUT RULES:
- Output ONLY the prompt text. No quotes, no explanation, no preamble, no markdown.
- Keep it between ${isVague ? '120 and 200' : '80 and 180'} words.
- Preserve the user's creative intent EXACTLY — do not change the subject or concept.${isVague ? ' But ADD visual context, scene, environment, and mood.' : ''}
- If the user's request is in another language, translate it faithfully to English first.
- ${preserveBrandName ? `KEEP THE EXACT BRAND NAME AND PRODUCT MODEL from the user's prompt. Do NOT remove or replace brand names. However, do NOT add any NEW brand names not already in the prompt.` : `REMOVE ALL brand names, product model names, company names. Replace with VISUAL DESCRIPTIONS ONLY. Example: instead of "MAN eTGX truck" write "a large modern European electric heavy-duty truck with a sleek aerodynamic cab, blue and silver livery".`}
- Vehicles, machines, technology MUST be MODERN, CONTEMPORARY (2024-era). NEVER vintage or retro.
- End the prompt with: "No text, no logos, no watermarks, no AI artifacts. Shot on film, 8K scan."

MODEL-SPECIFIC OPTIMIZATION (adapt density based on downstream model):
- Luma Photon / Photon Flash: respond best to cinematic scene descriptions + precise lighting terms ("golden hour backlit", "overcast window light"). Less keyword stacking, more narrative.
- Flux Pro / Flux Dev: handle long, dense prompts (150-200 words). Stack camera specs + lens + film stock + color grading.
- Flux Kontext Pro (edit/img2img): lead with the EDIT instruction ("change the background to...", "preserve the subject identity, add..."). Mention what to KEEP.
- DALL-E 3: shorter, more narrative prompts. Avoid technical stacking. Focus on subject + mood + simple scene.
- Ideogram V3: when text-in-image is required, quote the exact text inside double quotes.
- SeedDream / Soul / Nano-Banana (FAL): respond well to editorial/fashion references and brand-style tokens.

COMPOSITION PRINCIPLES (weave at least one into every prompt):
- Rule of thirds: subject off-center, eye-line on the upper third line
- Leading lines: architectural, natural, or light-based vectors guiding to the subject
- Negative space: intentional emptiness creating breathing room and tension
- Foreground / midground / background layering: creates depth perception
- Frame within a frame: doorway, window, arch, shadow — contextual framing

BRAND COLOR INTEGRATION RULE:
- NEVER append "add blue and orange" to the prompt. Weave colors DIEGETICALLY: a cobalt blue ceramic cup, a brass lamp casting amber light, a terracotta wall in the background, a client in a mustard wool coat.
- Colors come from props, wardrobe, light sources, surfaces, materials — never as flat color fills.

PRODUCT FIDELITY — ABSOLUTE RULE:
- When a product is referenced (via img2img reference image or exact name from the vault), preserve its EXACT identity: shape, proportions, color, logo placement, material finish.
- NEVER invent product features, certifications, awards, or performance claims in the prompt text.
- If the downstream pipeline has an img2img reference, DO NOT describe the product in detail — let the reference image do that work. Describe the SCENE around it.
- Quote exact product/brand names ONLY if they come from the user's prompt or vault context. Never guess or approximate.

UNIVERSE COMPLIANCE — MANDATORY:
- Every scene MUST anchor in the brand's communication universe (tone, palette, semiotic codes, photo direction from the BRAND CREATIVE DIRECTION block above).
- If a specific product is selected, use its PRODUCT UNIVERSE (palette, tone, photo_style, keywords) OVER the generic brand rules. Product universes override brand universes for product-specific content.
- Brand universes define creative TERRITORIES — draw visual inspiration from them, don't copy them literally.
- NEVER mix competitor visual codes with brand visual codes.

ANTI-HALLUCINATION — ZERO TOLERANCE:
- NEVER invent certifications, labels, or regulatory visual claims (ISO stamps, bio logos, "made in France" marks) unless explicitly provided.
- NEVER fabricate text, numbers, awards, or press mentions visible inside the image.
- NEVER invent statistics, percentages, or study results rendered on signs, packaging, or screens.
- NEVER guess legal/regulatory visual information (ingredient lists, allergens, nutritional facts).
- When in doubt, keep surfaces empty or use generic placeholder textures — NEVER fabricate claims.
- End with the anti-defect line to suppress hallucinated text: "No text, no logos, no watermarks, no AI artifacts."`;

  for (const m of enhanceModels) {
    try {
      const res = await fetch(`${APIPOD_BASE}/chat/completions`, {
        method: "POST",
        headers: { "Content-Type": "application/json", Authorization: `Bearer ${key}` },
        body: JSON.stringify({
          model: m,
          messages: [
            { role: "system", content: systemPrompt },
            { role: "user", content: rawPrompt },
          ],
          max_tokens: 400,
        }),
        signal: AbortSignal.timeout(12_000),
      });
      if (!res.ok) { console.log(`[enhancePrompt] ${m} returned ${res.status}, trying next...`); continue; }
      const data = await res.json();
      const enhanced = data.choices?.[0]?.message?.content?.trim();
      if (enhanced && enhanced.length > 20) {
        console.log(`[enhancePrompt] OK via ${m} (${Date.now() - t0}ms, brand=${!!brandCtx}): "${rawPrompt.slice(0, 40)}" → "${enhanced.slice(0, 120)}"`);
        return enhanced;
      }
    } catch (err) { console.log(`[enhancePrompt] ${m} error: ${err}`); }
  }
  return rawPrompt;
}

function lumaHeaders(): Record<string, string> {
  const key = Deno.env.get("LUMA_API_KEY");
  if (!key) throw new Error("LUMA_API_KEY not configured");
  return { "Content-Type": "application/json", Authorization: `Bearer ${key}` };
}

function higgsHeaders(): Record<string, string> {
  const accessKey = (Deno.env.get("HIGGSFIELD_API_KEY") || "").trim();
  const secretKey = (Deno.env.get("HIGGSFIELD_API_SECRET") || "").trim();
  if (!accessKey || !secretKey) throw new Error("HIGGSFIELD_API_KEY or HIGGSFIELD_API_SECRET not configured");
  const maskKey = (k: string) => k.length > 8 ? `${k.slice(0, 4)}...${k.slice(-4)}` : `${k.slice(0, 2)}***`;
  console.log(`[higgsHeaders] key=${maskKey(accessKey)} (${accessKey.length}c), secret=${maskKey(secretKey)} (${secretKey.length}c)`);
  return { "Content-Type": "application/json", Accept: "application/json", Authorization: `Key ${accessKey}:${secretKey}` };
}

function apipodHeaders(): Record<string, string> {
  const key = Deno.env.get("APIPOD_API_KEY");
  if (!key) throw new Error("APIPOD_API_KEY not configured");
  return { "Content-Type": "application/json", Authorization: `Bearer ${key}` };
}

