// Pick the closest allowed length for models with restricted durations
function pickClosestLength(requested: number, allowed: number[]): number {
  let best = allowed[0];
  let bestDist = Math.abs(requested - best);
  for (const v of allowed) {
    const d = Math.abs(requested - v);
    if (d < bestDist) { best = v; bestDist = d; }
  }
  return best;
}

async function callPolloVideoStart(
  pm: PolloModelEntry,
  opts: { prompt: string; imageUrl?: string; durationSec: number; aspectRatio: string },
): Promise<{ ok: true; taskId: string } | { ok: false; error: string }> {
  const key = Deno.env.get("POLLO_API_KEY");
  if (!key) return { ok: false, error: "POLLO_API_KEY not configured" };
  try {
    // Resolve duration: use allowedLengths if model has restrictions, else defaultLength as floor
    let length = opts.durationSec;
    if (pm.allowedLengths) {
      length = pickClosestLength(opts.durationSec, pm.allowedLengths);
    } else if (opts.durationSec < pm.defaultLength) {
      length = pm.defaultLength;
    }

    // Truncate prompt if model has a max prompt length
    let prompt = opts.prompt;
    if (pm.maxPromptLen && prompt.length > pm.maxPromptLen) {
      prompt = prompt.slice(0, pm.maxPromptLen - 1) + "…";
      console.log(`[pollo] Truncated prompt to ${pm.maxPromptLen} chars for ${pm.polloPath}`);
    }

    const input: Record<string, unknown> = { prompt, length };
    if (opts.imageUrl) {
      // img2video: most Pollo models reject aspectRatio (additionalProperties: false)
      input.image = opts.imageUrl;
    } else {
      // text2video: aspectRatio is accepted
      input.aspectRatio = opts.aspectRatio;
    }

    console.log(`[pollo] POST ${pm.polloPath} length=${length} promptLen=${prompt.length} hasImage=${!!opts.imageUrl}`);
    const res = await fetch(`${POLLO_BASE}${pm.polloPath}`, {
      method: "POST",
      headers: { "Content-Type": "application/json", "x-api-key": key },
      body: JSON.stringify({ input, webhookUrl: POLLO_WEBHOOK_URL }),
      signal: AbortSignal.timeout(20_000),
    });
    const txt = await res.text().catch(() => "");
    if (!res.ok) return { ok: false, error: `Pollo ${pm.polloPath} HTTP ${res.status}: ${txt.slice(0, 300)}` };
    let data: any;
    try { data = JSON.parse(txt); } catch { return { ok: false, error: `Pollo ${pm.polloPath}: non-JSON response` }; }
    // Pollo wraps responses: { code, message, data: { taskId } } or flat { taskId }
    const taskId = data.data?.taskId || data.taskId;
    if (!taskId) return { ok: false, error: `Pollo ${pm.polloPath}: no taskId (got: ${JSON.stringify(data).slice(0, 200)})` };
    return { ok: true, taskId };
  } catch (err) {
    return { ok: false, error: `Pollo ${pm.polloPath} error: ${err}` };
  }
}

async function callPolloVideoStatus(taskId: string): Promise<{ state: string; videoUrl?: string; error?: string }> {
  // ── Check KV first (populated by webhook — instant response) ──
  const cached = await kvGetPolloResult(taskId);
  if (cached && (cached.state === "completed" || cached.state === "failed")) {
    console.log(`[pollo-status] KV hit for ${taskId.slice(0, 12)}: state=${cached.state}`);
    return cached;
  }

  // ── Fallback: poll Pollo API directly ──
  const key = Deno.env.get("POLLO_API_KEY");
  if (!key) return { state: "error", error: "POLLO_API_KEY not configured" };
  try {
    const res = await fetch(`${POLLO_BASE}/generation/${taskId}/status`, {
      headers: { "x-api-key": key },
      signal: AbortSignal.timeout(15_000),
    });
    const raw = await res.json();
    // Pollo may wrap: { code, data: { generations: [...] } } or flat { generations: [...] }
    const data = raw?.data || raw;
    // Pollo status: "waiting" | "processing" | "succeed" | "failed"
    const gen = data?.generations?.[0];
    if (gen?.status === "succeed" && gen?.url) {
      const result = { state: "completed" as const, videoUrl: gen.url };
      await kvSetPolloResult(taskId, result); // cache for future polls
      return result;
    }
    if (gen?.status === "failed") {
      const result = { state: "failed" as const, error: gen?.failMsg || "Pollo generation failed" };
      await kvSetPolloResult(taskId, result);
      return result;
    }
    // Map Pollo states to our states
    const st = gen?.status || data?.status || "processing";
    return { state: st === "waiting" ? "queued" : "processing" };
  } catch (err) {
    return { state: "error", error: `Pollo status error: ${err}` };
  }
}

// Submit to FAL queue. Returns { requestId, statusUrl, responseUrl }.
async function callFalVideoStart(falPath: string, body: any): Promise<{ ok: true; requestId: string; statusUrl: string; responseUrl: string } | { ok: false; error: string }> {
  const key = Deno.env.get("FAL_API_KEY");
  if (!key) return { ok: false, error: "FAL_API_KEY not configured" };
  try {
    const res = await fetch(`https://queue.fal.run/${falPath}`, {
      method: "POST",
      headers: { "Content-Type": "application/json", Authorization: `Key ${key}` },
      body: JSON.stringify(body),
      signal: AbortSignal.timeout(20_000),
    });
    const txt = await res.text().catch(() => "");
    if (!res.ok) return { ok: false, error: `FAL ${falPath} HTTP ${res.status}: ${txt.slice(0, 300)}` };
    let data: any;
    try { data = JSON.parse(txt); } catch { return { ok: false, error: `FAL ${falPath}: non-JSON response` }; }
    if (!data.request_id || !data.status_url || !data.response_url) {
      return { ok: false, error: `FAL ${falPath}: missing request_id/status_url/response_url (got: ${JSON.stringify(data).slice(0, 200)})` };
    }
    return { ok: true, requestId: data.request_id, statusUrl: data.status_url, responseUrl: data.response_url };
  } catch (err) {
    return { ok: false, error: `FAL ${falPath} error: ${err}` };
  }
}

// Poll FAL status and fetch final video url when completed.
async function callFalVideoStatus(statusUrl: string, responseUrl: string): Promise<{ state: "queued" | "dreaming" | "completed" | "failed" | "error"; videoUrl?: string | null; error?: string }> {
  const key = Deno.env.get("FAL_API_KEY");
  if (!key) return { state: "error", error: "FAL_API_KEY not configured" };
  try {
    const sres = await fetch(statusUrl, { headers: { Authorization: `Key ${key}` }, signal: AbortSignal.timeout(10_000) });
    if (!sres.ok) {
      if (sres.status === 404) return { state: "queued" };
      return { state: "queued" };
    }
    const sdata = await sres.json();
    const status = String(sdata.status || "").toUpperCase();
    if (status === "COMPLETED") {
      const rres = await fetch(responseUrl, { headers: { Authorization: `Key ${key}` }, signal: AbortSignal.timeout(15_000) });
      if (!rres.ok) return { state: "error", error: `FAL response HTTP ${rres.status}` };
      const rdata = await rres.json();
      const videoUrl = rdata.video?.url || rdata.output?.video?.url || rdata.video_url || null;
      return { state: "completed", videoUrl };
    }
    if (status === "FAILED" || status === "ERROR" || status === "CANCELED") {
      return { state: "failed", error: sdata.error || "FAL generation failed" };
    }
    return { state: "dreaming" };
  } catch (err) {
    return { state: "error", error: `${err}` };
  }
}

// Pack / unpack the generationId used for FAL polling (stateless: URLs encoded in the id).
function packFalGenerationId(statusUrl: string, responseUrl: string): string {
  try {
    const payload = JSON.stringify({ s: statusUrl, r: responseUrl });
    return "fal:" + btoa(payload);
  } catch {
    return "fal:" + btoa(`${statusUrl}|${responseUrl}`);
  }
}
function unpackFalGenerationId(id: string): { statusUrl: string; responseUrl: string } | null {
  if (!id.startsWith("fal:")) return null;
  try {
    const decoded = atob(id.slice(4));
    const parsed = JSON.parse(decoded);
    if (parsed.s && parsed.r) return { statusUrl: parsed.s, responseUrl: parsed.r };
  } catch {}
  return null;
}

// ── IMAGE GENERATION (secondary provider — submit + polling) ──
async function generateImageHf(req: { prompt: string; model: string; aspectRatio?: string }) {
  const mapping = hfImageModelMap[req.model];
  if (!mapping) throw new Error(`Unknown secondary image model: ${req.model}`);
  const start = Date.now();
  const ar = req.aspectRatio || mapping.aspectRatio;
  console.log(`[image-hf] model=${req.model} → chain=${mapping.hfModels.join(",")}, aspect=${ar}`);

  const hfBody: any = { prompt: req.prompt, aspect_ratio: ar, resolution: "2K" };
  const result = await hfFetchWithFallback(mapping.hfModels, hfBody, "image-hf");
  if (!result.ok) throw new Error(`Image generation failed: ${result.error}`);

  const { data, model: usedModel } = result;
  const requestId = data.request_id;
  console.log(`[image-hf] Submitted ${usedModel}, requestId=${requestId} (${Date.now() - start}ms)`);

  // Poll for completion (max 90s, every 3s)
  let elapsed = 0;
  while (elapsed < 90_000) {
    await new Promise(r => setTimeout(r, 3_000));
    elapsed += 3_000;
    try {
      const statusUrl = `${HIGGSFIELD_BASE}/requests/${requestId}/status`;
      const pollRes = await fetch(statusUrl, { headers: higgsHeaders(), signal: AbortSignal.timeout(10_000) });
      if (!pollRes.ok) { console.log(`[image-hf] poll ${pollRes.status} for ${requestId} (${elapsed / 1000}s)`); continue; }
      const pollData = await pollRes.json();
      const state = pollData.status;
      console.log(`[image-hf] poll ${requestId}: state=${state} (${elapsed / 1000}s)`);
      if (state === "completed") {
        const imageUrl = pollData.images?.[0]?.url;
        if (!imageUrl) throw new Error(`Completed but no URL: ${JSON.stringify(pollData).slice(0, 300)}`);
        console.log(`[image-hf] ${usedModel} OK in ${Date.now() - start}ms`);
        return { model: req.model, provider: usedModel.split("/").slice(0, 2).join("/"), imageUrl, latencyMs: Date.now() - start };
      }
      if (state === "failed") throw new Error(`Image failed: ${pollData.error || "unknown"}`);
      if (state === "nsfw") throw new Error("Content failed moderation");
    } catch (pollErr) {
      if (pollErr instanceof Error && (pollErr.message.startsWith("Image failed") || pollErr.message.startsWith("Completed") || pollErr.message.startsWith("Content failed"))) throw pollErr;
      console.log(`[image-hf] poll error (continuing): ${pollErr}`);
    }
  }
  throw new Error(`Image timeout (90s), requestId=${requestId}`);
}

// ── LEONARDO AI IMAGE GENERATION (submit + poll) ──
function leonardoHeaders(): Record<string, string> {
  const key = Deno.env.get("LEONARDO_API_KEY");
  if (!key) throw new Error("LEONARDO_API_KEY not configured");
  return { "Content-Type": "application/json", Authorization: `Bearer ${key}`, accept: "application/json" };
}

function leonardoAspectToDims(ar: string): { width: number; height: number } {
  const map: Record<string, { width: number; height: number }> = {
    "1:1":  { width: 1024, height: 1024 },
    "4:3":  { width: 1024, height: 768 },
    "3:4":  { width: 768, height: 1024 },
    "16:9": { width: 1024, height: 576 },
    "9:16": { width: 576, height: 1024 },
    "3:2":  { width: 1024, height: 683 },
    "2:3":  { width: 683, height: 1024 },
  };
  return map[ar] || { width: 1024, height: 768 };
}

async function generateImageLeonardo(req: { prompt: string; model: string; aspectRatio?: string }) {
  const mapping = leonardoImageModelMap[req.model];
  if (!mapping) throw new Error(`Unknown Leonardo model: ${req.model}`);
  const start = Date.now();
  const ar = req.aspectRatio || mapping.aspectRatio;
  const dims = leonardoAspectToDims(ar);
  const isLucid = mapping.leonardoModelId.startsWith("7b5922") || mapping.leonardoModelId.startsWith("05ce00");
  // Alchemy NOT supported on: Lucid Origin, Lucid Realism, Flux Dev, Flux Schnell, Leonardo Lightning (same underlying model)
  const noAlchemy = isLucid || req.model.includes("flux-dev") || req.model.includes("flux-schnell") || req.model === "leonardo-lightning";
  console.log(`[image-leonardo] model=${req.model} → Leonardo ${mapping.leonardoModelId.slice(0, 8)}, aspect=${ar}, dims=${dims.width}x${dims.height}, alchemy=${!noAlchemy}`);

  // Step 1: Submit generation (v1 API)
  // contrast is REQUIRED (3=Low, 3.5=Medium, 4=High)
  const submitBody: any = {
    prompt: req.prompt,
    modelId: mapping.leonardoModelId,
    width: dims.width,
    height: dims.height,
    num_images: 1,
    contrast: 3.5,
    styleUUID: mapping.styleUUID || "111dc692-d470-4eec-b791-3475abac4c46",
  };
  // Only add alchemy for models that support it
  if (!noAlchemy) {
    submitBody.alchemy = true;
  }
  const submitRes = await fetch(`${LEONARDO_BASE}/generations`, {
    method: "POST",
    headers: leonardoHeaders(),
    body: JSON.stringify(submitBody),
  });
  if (!submitRes.ok) { const b = await submitRes.text(); throw new Error(`Leonardo submit ${submitRes.status}: ${b}`); }
  const submitData = await submitRes.json();
  const generationId = submitData.sdGenerationJob?.generationId;
  if (!generationId) throw new Error(`Leonardo: no generationId returned: ${JSON.stringify(submitData).slice(0, 300)}`);
  console.log(`[image-leonardo] submitted generationId=${generationId} (${Date.now() - start}ms)`);

  // Step 2: Poll for completion (max 120s, every 4s)
  let elapsed = 0;
  while (elapsed < 120_000) {
    await new Promise(r => setTimeout(r, 4_000));
    elapsed += 4_000;
    try {
      const pollRes = await fetch(`${LEONARDO_BASE}/generations/${generationId}`, {
        headers: leonardoHeaders(),
      });
      if (!pollRes.ok) { console.log(`[image-leonardo] poll ${pollRes.status} (${elapsed / 1000}s, continuing)`); continue; }
      const pollData = await pollRes.json();
      const gen = pollData.generations_by_pk;
      if (!gen) { console.log(`[image-leonardo] no generations_by_pk yet (${elapsed / 1000}s)`); continue; }
      const status = gen.status;
      console.log(`[image-leonardo] poll ${generationId}: status=${status} (${elapsed / 1000}s)`);
      if (status === "COMPLETE") {
        const imageUrl = gen.generated_images?.[0]?.url;
        if (!imageUrl) throw new Error(`Leonardo completed but no URL: ${JSON.stringify(gen).slice(0, 300)}`);
        console.log(`[image-leonardo] OK in ${Date.now() - start}ms`);
        return { model: req.model, provider: `leonardo/${mapping.leonardoModelId.slice(0, 8)}`, imageUrl, latencyMs: Date.now() - start };
      }
      if (status === "FAILED") {
        const failReason = gen.generated_images?.[0]?.failReason || gen.failReason || "unknown";
        throw new Error(`Leonardo generation failed: ${failReason}`);
      }
      // PENDING → continue polling
    } catch (pollErr) {
      if (pollErr instanceof Error && (pollErr.message.startsWith("Leonardo completed") || pollErr.message.startsWith("Leonardo generation failed"))) throw pollErr;
      console.log(`[image-leonardo] poll error (continuing): ${pollErr}`);
    }
  }
  throw new Error(`Leonardo image timeout (120s), generationId=${generationId}`);
}

