// Stripe Webhook — handles subscription lifecycle events
app.post("/stripe/webhook", async (c) => {
  try {
    if (!STRIPE_SECRET_KEY) return c.json({ error: "Stripe not configured" }, 500);

    const rawBody = await c.req.text();
    const sig = c.req.header("stripe-signature") || "";

    // Verify webhook signature if secret is set
    if (STRIPE_WEBHOOK_SECRET && sig) {
      // Use Stripe's signature verification via crypto
      const encoder = new TextEncoder();
      const parts = sig.split(",");
      const tPart = parts.find((p: string) => p.startsWith("t="))?.split("=")[1];
      const v1Part = parts.find((p: string) => p.startsWith("v1="))?.split("=")[1];

      if (tPart && v1Part) {
        const payload = `${tPart}.${rawBody}`;
        const key = await crypto.subtle.importKey(
          "raw",
          encoder.encode(STRIPE_WEBHOOK_SECRET),
          { name: "HMAC", hash: "SHA-256" },
          false,
          ["sign"]
        );
        const signature = await crypto.subtle.sign("HMAC", key, encoder.encode(payload));
        const expectedSig = Array.from(new Uint8Array(signature))
          .map((b) => b.toString(16).padStart(2, "0"))
          .join("");

        if (expectedSig !== v1Part) {
          console.log("[stripe webhook] signature verification FAILED");
          return c.json({ error: "Invalid signature" }, 400);
        }
      }
    }

    const event = JSON.parse(rawBody);
    console.log(`[stripe webhook] event=${event.type} id=${event.id}`);

    switch (event.type) {
      case "checkout.session.completed": {
        const session = event.data.object;
        const userId = session.metadata?.userId;
        const plan = session.metadata?.plan;
        const pack = session.metadata?.pack;

        if (userId && pack) {
          // Credit pack purchase (one-time)
          const profile = await getOrCreateProfile(userId, session.customer_email || "");
          const packContents = CREDIT_PACK_CONTENTS[pack] || 0;
          profile.credits = (profile.credits || 0) + packContents;
          profile.stripeCustomerId = session.customer;
          await kv.set(`user:${userId}`, profile);
          await logEvent("pack_purchased", { userId, pack, contents: packContents });
          console.log(`[stripe webhook] pack=${pack} (+${packContents} contents) for user=${userId.slice(0, 8)}`);
        } else if (userId && plan) {
          // Subscription plan
          const profile = await getOrCreateProfile(userId, session.customer_email || "");
          profile.plan = plan;
          profile.contents = PLAN_CONTENTS[plan] || PLAN_CONTENTS.free;
          profile.credits = PLAN_CREDITS[plan] || PLAN_CREDITS.free;
          profile.creditsUsed = 0;
          profile.stripeCustomerId = session.customer;
          profile.stripeSubscriptionId = session.subscription;
          await kv.set(`user:${userId}`, profile);
          await logEvent("subscription_created", { userId, plan, stripeCustomer: session.customer });

          // Send confirmation email
          const name = profile.name || profile.email?.split("@")[0] || "there";
          if (profile.email) {
            const { subject, html } = emailPlanConfirmation(name, plan, profile.credits);
            sendEmail(profile.email, subject, html).catch(() => {});
          }
          console.log(`[stripe webhook] activated plan=${plan} for user=${userId.slice(0, 8)} contents=${profile.contents}`);
        }
        break;
      }

      case "invoice.paid": {
        // Monthly renewal — reset credits
        const invoice = event.data.object;
        const subscriptionId = invoice.subscription;
        if (subscriptionId && invoice.billing_reason === "subscription_cycle") {
          // Find user by subscription ID
          const allUsers = await kv.getByPrefix("user:").catch(() => []);
          const userEntry = (allUsers as any[]).find((u: any) => u?.stripeSubscriptionId === subscriptionId);
          if (userEntry) {
            const plan = userEntry.plan;
            userEntry.credits = PLAN_CREDITS[plan] || PLAN_CREDITS.free;
            userEntry.creditsUsed = 0;
            await kv.set(`user:${userEntry.userId}`, userEntry);
            console.log(`[stripe webhook] renewed credits for user=${userEntry.userId?.slice(0, 8)} plan=${plan}`);
          }
        }
        break;
      }

      case "customer.subscription.deleted": {
        // Subscription canceled — downgrade to free
        const sub = event.data.object;
        const userId = sub.metadata?.userId;
        if (userId) {
          const profile = await kv.get(`user:${userId}`).catch(() => null);
          if (profile) {
            profile.plan = "free";
            profile.credits = PLAN_CREDITS.free;
            profile.creditsUsed = 0;
            profile.stripeSubscriptionId = null;
            await kv.set(`user:${userId}`, profile);
            await logEvent("subscription_canceled", { userId, previousPlan: sub.metadata?.plan });
            console.log(`[stripe webhook] canceled → free for user=${userId.slice(0, 8)}`);
          }
        }
        break;
      }

      case "customer.subscription.updated": {
        // Plan change (upgrade/downgrade)
        const sub = event.data.object;
        const userId = sub.metadata?.userId;
        const newPlan = sub.metadata?.plan;
        if (userId && newPlan) {
          const profile = await kv.get(`user:${userId}`).catch(() => null);
          if (profile && profile.plan !== newPlan) {
            profile.plan = newPlan;
            profile.credits = PLAN_CREDITS[newPlan] || PLAN_CREDITS.free;
            profile.creditsUsed = 0;
            profile.stripeSubscriptionId = sub.id;
            await kv.set(`user:${userId}`, profile);
            console.log(`[stripe webhook] plan updated to ${newPlan} for user=${userId.slice(0, 8)}`);
          }
        }
        break;
      }

      default:
        console.log(`[stripe webhook] unhandled event type: ${event.type}`);
    }

    return c.json({ received: true });
  } catch (err) {
    console.log("[stripe webhook] error:", err);
    return c.json({ error: `Webhook error: ${err}` }, 500);
  }
});

// ══════════════════════════════════════════════════════════════
// GENERATION ROUTES
// ══════════════════════════════════════════════════════════════

app.post("/generate/text-multi", async (c) => {
  const t0 = Date.now();
  try {
    // Auth: soft — don't block generation if auth fails
    let user: AuthUser | null = null;
    try {
      user = await getUser(c);
      console.log(`[text-multi] auth: ${user ? `user=${user.id}` : "guest (no valid JWT)"}`);
    } catch (authErr) {
      console.log(`[text-multi] auth error (continuing as guest):`, authErr);
    }

    const body = c.get?.("parsedBody") || await c.req.json();
    const { prompt, models, systemPrompt, maxTokens } = body;
    console.log(`[text-multi] prompt="${prompt?.slice(0, 60)}", models=${JSON.stringify(models)}, user=${user?.id || "guest"}`);
    if (!prompt || !models?.length) return c.json({ error: "prompt and models required" }, 400);

    const MODEL_TIMEOUT = 90_000; // 90s per model (generateText has 30s internal timeout per attempt, chain can have 3 models)
    const results = await Promise.all(
      models.map(async (model: string) => {
        const credits = getModelCreditCost("text", model);
        if (user) deductCredit(user.id, credits).catch(() => {});
        try {
          console.log(`[text-multi] calling generateText(${model}), credits=${credits}...`);
          const result = await Promise.race([
            generateText({ prompt, model, systemPrompt, maxTokens }),
            new Promise<never>((_, reject) => setTimeout(() => reject(new Error(`Timeout: ${model} >${MODEL_TIMEOUT}ms`)), MODEL_TIMEOUT)),
          ]);
          console.log(`[text-multi] ${model} OK in ${Date.now() - t0}ms, provider=${result.provider}`);
          if (user) logEvent("generation", { userId: user.id, type: "text", model }).catch(() => {});
          logCost({ type: "text", model, provider: result.provider, costUsd: getProviderCost(result.provider, "text"), revenueEur: getModelRevenue("text", model), latencyMs: result.latencyMs, userId: user?.id || "guest", success: true }).catch(() => {});
          return { success: true, result, creditCost: credits };
        } catch (err) {
          console.log(`[text-multi] ${model} FAILED:`, err);
          logCost({ type: "text", model, provider: "unknown", costUsd: 0, revenueEur: 0, latencyMs: Date.now() - t0, userId: user?.id || "guest", success: false }).catch(() => {});
          return { success: false, error: String(err) };
        }
      })
    );
    console.log(`[text-multi] done in ${Date.now() - t0}ms, ${results.length} results`);
    return c.json({ success: true, results });
  } catch (err) {
    console.log(`[text-multi] FATAL error after ${Date.now() - t0}ms:`, err);
    return c.json({ success: false, error: `Text generation error: ${err}` }, 500);
  }
});

