app.post("/generate/pollo-image", async (c) => {
  const t0 = Date.now();
  try {
    let user: AuthUser | null = null; try { user = await getUser(c); } catch {}
    const pb = c.get("parsedBody") || {};
    const prompt = pb.prompt;
    const modelName = pb.model || "nano-banana";
    if (!prompt) return c.json({ error: "prompt required" }, 400);
    const endpoint = pb.imageUrl ? "/generation/image2image" : "/generation/text2image";
    const input: Record<string, unknown> = { prompt, modelName, aspectRatio: pb.aspectRatio || "1:1" };
    if (pb.imageUrl) input.imageUrl = pb.imageUrl;
    if (pb.negativePrompt) input.negativePrompt = pb.negativePrompt;
    if (pb.style) input.style = pb.style;
    if (pb.resolution) input.resolution = pb.resolution;
    if (pb.numOutputs) input.numOutputs = Math.min(Number(pb.numOutputs), 4);
    console.log(`[pollo-image] ${endpoint} model=${modelName} hasRef=${!!pb.imageUrl}`);
    const result = await callPolloTool(endpoint, { input });
    if (!result.ok) return c.json({ success: false, error: result.error }, 500);
    if (user) deductCredit(user.id, getModelCreditCost("image", modelName)).catch(() => {});
    return c.json({ success: true, generationId: `pollo:${result.taskId}`, state: "queued", model: modelName });
  } catch (err) { return c.json({ success: false, error: `${err}` }, 500); }
});

// ── VIDEO STATUS (poll Luma or secondary provider once, return current state) ──
app.get("/generate/video-status", async (c) => {
  const t0 = Date.now();
  try {
    const rawId = c.req.query("id");
    if (!rawId) return c.json({ error: "id required" }, 400);

    // Detect Pollo via "pollo:" prefix
    if (rawId.startsWith("pollo:")) {
      const taskId = rawId.slice(6);
      const r = await callPolloVideoStatus(taskId);
      console.log(`[video-status] POLLO state=${r.state} (${Date.now() - t0}ms)`);
      if (r.state === "completed") return c.json({ success: true, state: "completed", videoUrl: r.videoUrl || null });
      if (r.state === "failed") return c.json({ success: true, state: "failed", error: r.error || "Video generation failed" });
      if (r.state === "error") return c.json({ success: false, state: "error", error: r.error });
      return c.json({ success: true, state: r.state });
    }

    // Detect FAL via "fal:" prefix
    if (rawId.startsWith("fal:")) {
      const unpacked = unpackFalGenerationId(rawId);
      if (!unpacked) {
        console.log(`[video-status] FAL: failed to unpack generationId`);
        return c.json({ success: false, state: "error", error: "Invalid FAL generation id" }, 400);
      }
      const r = await callFalVideoStatus(unpacked.statusUrl, unpacked.responseUrl);
      console.log(`[video-status] FAL state=${r.state} (${Date.now() - t0}ms)`);
      if (r.state === "completed") return c.json({ success: true, state: "completed", videoUrl: r.videoUrl || null });
      if (r.state === "failed") return c.json({ success: true, state: "failed", error: r.error || "Video generation failed" });
      if (r.state === "error") return c.json({ success: false, state: "error", error: r.error });
      return c.json({ success: true, state: r.state });
    }

    // Detect secondary provider via "hf:" prefix
    if (rawId.startsWith("hf:")) {
      const requestId = rawId.slice(3);
      const statusUrl = `${HIGGSFIELD_BASE}/requests/${requestId}/status`;
      const hfRes = await fetch(statusUrl, { headers: higgsHeaders(), signal: AbortSignal.timeout(10_000) });
      if (hfRes.ok) {
        const data = await hfRes.json();
        const status = data.status;
        if (status === "completed") {
          const videoUrl = data.video?.url || null;
          console.log(`[video-status] Secondary ${requestId} COMPLETED (${Date.now() - t0}ms)`);
          return c.json({ success: true, state: "completed", videoUrl });
        }
        if (status === "failed") {
          console.log(`[video-status] Secondary ${requestId} FAILED: ${data.error}`);
          return c.json({ success: true, state: "failed", error: data.error || "Video generation failed" });
        }
        if (status === "nsfw") {
          return c.json({ success: true, state: "failed", error: "Content failed moderation" });
        }
        console.log(`[video-status] Secondary ${requestId} state=${status} (${Date.now() - t0}ms)`);
        return c.json({ success: true, state: status === "in_progress" ? "dreaming" : "queued" });
      }
      console.log(`[video-status] Secondary poll ${hfRes.status} for ${requestId}`);
      return c.json({ success: true, state: "queued" });
    }

    // Luma path
    const generationId = rawId;
    const pollRes = await fetch(`${LUMA_BASE}/generations/${generationId}`, {
      headers: lumaHeaders(),
    });
    if (!pollRes.ok) {
      const errBody = await pollRes.text();
      console.log(`[video-status] Luma poll ${pollRes.status}: ${errBody.slice(0, 200)}`);
      return c.json({ success: false, state: "error", error: `Poll error ${pollRes.status}` }, 500);
    }
    const data = await pollRes.json();
    const state = data.state;

    if (state === "completed") {
      const videoUrl = data.assets?.video;
      console.log(`[video-status] ${generationId} COMPLETED in ${Date.now() - t0}ms`);
      return c.json({ success: true, state: "completed", videoUrl: videoUrl || null });
    }
    if (state === "failed") {
      console.log(`[video-status] ${generationId} FAILED: ${data.failure_reason}`);
      return c.json({ success: true, state: "failed", error: data.failure_reason || "Video generation failed" });
    }

    console.log(`[video-status] ${generationId} state=${state} (${Date.now() - t0}ms)`);
    return c.json({ success: true, state });
  } catch (err) {
    console.log(`[video-status] error:`, err);
    return c.json({ success: false, state: "error", error: `Status check failed: ${err}` }, 500);
  }
});

