app.post("/generate/audio-multi", async (c) => {
  // Redirect to the start endpoint — frontend should use audio-start + audio-poll instead
  const t0 = Date.now();
  try {
    let user: AuthUser | null = null;
    try { user = await getUser(c); } catch { }
    const body = c.get?.("parsedBody") || await c.req.json();
    const { prompt, models, instrumental, lyrics, title, style } = body;
    if (!prompt || !models?.length) return c.json({ error: "prompt and models required" }, 400);

    const results = await Promise.all(
      models.map(async (model: string) => {
        if (user) deductCredit(user.id, 3).catch(() => {});
        try {
          const { taskId, sunoModel } = await sunoStartGeneration({ prompt, model, instrumental, lyrics, title, style });
          // Quick poll: try up to 45s within edge function limit
          for (let i = 0; i < 8; i++) {
            await new Promise(r => setTimeout(r, 5000));
            const poll = await sunoPollStatus(taskId);
            if (poll.status === "DONE") {
              return { success: true, result: { model, provider: `suno/${sunoModel}`, audioUrl: poll.track.audioUrl, latencyMs: Date.now() - t0, title: poll.track.title, duration: poll.track.duration, imageUrl: poll.track.imageUrl, sunoTaskId: taskId, sunoAudioId: poll.track.id } };
            }
            if (poll.status === "FAILED") return { success: false, error: poll.error };
          }
          // Not ready yet — return taskId so frontend can poll
          return { success: false, pending: true, taskId, model, error: "Still generating. Use /generate/audio-poll?taskId=" + taskId };
        } catch (err) {
          return { success: false, error: String(err) };
        }
      })
    );
    console.log(`[audio-multi] done in ${Date.now() - t0}ms`);
    return c.json({ success: true, results });
  } catch (err) {
    console.log(`[audio-multi] FATAL:`, err);
    return c.json({ success: false, error: `Audio generation error: ${err}` }, 500);
  }
});

// ══════════════════════════════════════════════════════════════
// ELEVENLABS MUSIC — synchronous compose → storage → signed URL
// ══════════════════════════════════════════════════════════════

async function elevenLabsCompose(opts: {
  prompt: string;
  durationMs: number;
  instrumental?: boolean;
}): Promise<{ audioUrl: string; durationMs: number; storagePath: string }> {
  const key = Deno.env.get("ELEVENLABS_API_KEY");
  if (!key) throw new Error("ELEVENLABS_API_KEY not set");

  const duration = Math.max(3000, Math.min(600000, opts.durationMs || 20000));
  const body: Record<string, unknown> = {
    prompt: opts.prompt,
    music_length_ms: duration,
    model_id: "music_v1",
  };
  if (opts.instrumental) body.force_instrumental = true;

  console.log(`[elevenlabs/music] POST /v1/music duration=${duration}ms prompt="${opts.prompt.slice(0, 80)}"`);
  const res = await fetch("https://api.elevenlabs.io/v1/music?output_format=mp3_44100_128", {
    method: "POST",
    headers: { "xi-api-key": key, "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });

  if (!res.ok) {
    const errText = await res.text();
    console.log(`[elevenlabs/music] error ${res.status}: ${errText.slice(0, 300)}`);
    // Try to extract bad_prompt suggestion
    try {
      const errJson = JSON.parse(errText);
      const detail = errJson?.detail;
      if (detail?.status === "bad_prompt" && detail?.data?.prompt_suggestion) {
        throw new Error(`ElevenLabs rejected prompt (likely copyrighted). Suggestion: ${detail.data.prompt_suggestion}`);
      }
    } catch { /* fallthrough */ }
    throw new Error(`ElevenLabs error ${res.status}: ${errText.slice(0, 200)}`);
  }

  const bytes = new Uint8Array(await res.arrayBuffer());
  const path = `elevenlabs-music/${Date.now()}-${crypto.randomUUID()}.mp3`;
  const { error: upErr } = await supabase.storage.from("generations").upload(path, bytes, { contentType: "audio/mpeg", upsert: false });
  if (upErr) throw new Error(`Storage upload failed: ${upErr.message}`);
  const { data: pubData } = supabase.storage.from("generations").getPublicUrl(path);
  console.log(`[elevenlabs/music] uploaded ${bytes.length} bytes → ${pubData.publicUrl}`);
  return { audioUrl: pubData.publicUrl, durationMs: duration, storagePath: path };
}

