// POST /vault/load — CORS-safe vault read (token in body)
app.post("/vault/load", async (c) => {
  try {
    const user = await requireAuth(c);
    let rawVault = await kv.get(`vault:${user.id}`);
    // Auto-fix: if vault has a nested "vault" key from old onboarding bug, flatten it
    if (rawVault && rawVault.vault && typeof rawVault.vault === "object" && !Array.isArray(rawVault.vault)) {
      const { vault: nested, ...rest } = rawVault;
      rawVault = { ...rest, ...nested };
      await saveVaultToKV(user.id, rawVault);
      console.log(`[vault/load] Auto-fixed nested vault.vault for user=${user.id.slice(0,8)}`);
    }
    const vault = syncVaultNames(rawVault);
    console.log(`[vault/load] user ${user.id}: vault ${vault ? "found" : "not found"} brand="${vault?.brandName || ""}" company="${vault?.company_name || ""}" onboarding=${vault?.onboarding_completed}`);
    return c.json({ success: true, vault: vault || null });
  } catch (err) { return c.json({ success: false, error: String(err) }, 500); }
});

// POST /vault — Save vault data (CORS-safe: token in body)
app.post("/vault", async (c) => {
  try {
    const body = c.get("parsedBody") || await c.req.json().catch(() => ({}));
    const { _token, ...rawData } = body;
    // Flatten if caller sent { vault: {...} } wrapper (legacy onboarding format)
    const data = (rawData.vault && typeof rawData.vault === "object" && !Array.isArray(rawData.vault) && Object.keys(rawData).length === 1)
      ? rawData.vault
      : rawData;
    console.log(`[vault/save] incoming keys: [${Object.keys(data).join(",")}] company_name="${data.company_name || "NONE"}" brandName="${data.brandName || "NONE"}"`);

    // ── RESET: if body has _reset=true, wipe vault entirely ──
    if (data._reset === true) {
      const user = await requireAuth(c);
      const freshVault = { userId: user.id, updatedAt: new Date().toISOString() };
      await saveVaultToKV(user.id, freshVault);
      console.log(`[vault/reset] user=${user.id.slice(0, 8)} — vault wiped via _reset flag`);
      return c.json({ success: true, vault: freshVault });
    }

    // If body only has _token → it's a read
    if (Object.keys(data).length === 0) {
      const user = await requireAuth(c);
      const vault = await kv.get(`vault:${user.id}`);
      // Auto-fix: if vault has a nested "vault" key from old onboarding bug, flatten it
      if (vault && vault.vault && typeof vault.vault === "object" && !Array.isArray(vault.vault)) {
        const { vault: nested, ...rest } = vault;
        const fixed = { ...rest, ...nested };
        await saveVaultToKV(user.id, fixed);
        console.log(`[vault/read] Auto-fixed nested vault.vault for user=${user.id.slice(0,8)}`);
        return c.json({ success: true, vault: fixed });
      }
      return c.json({ success: true, vault: vault || null });
    }
    // Otherwise it's a write
    const user = await requireAuth(c);
    const existing = await kv.get(`vault:${user.id}`) || {};
    const merged = { ...existing, ...data, userId: user.id, updatedAt: new Date().toISOString() };
    // Keep brandName and company_name in sync — whichever is newer wins
    if (data.brandName && !data.company_name) merged.company_name = data.brandName;
    if (data.company_name && !data.brandName) merged.brandName = data.company_name;
    // If both exist in merged but mismatch, prefer the one from incoming data
    if (merged.brandName && merged.company_name && merged.brandName !== merged.company_name) {
      const canonical = data.brandName || data.company_name || merged.brandName;
      merged.brandName = canonical;
      merged.company_name = canonical;
    }
    await saveVaultToKV(user.id, merged);
    console.log(`[vault/save] user=${user.id.slice(0,8)} brandName="${merged.brandName}" company_name="${merged.company_name}"`);
    return c.json({ success: true, vault: merged });
  } catch (err) { return c.json({ success: false, error: String(err) }, 500); }
});

// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
// BRAND ENGINE — Strategy synthesis & prompt enrichment
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

// POST /brand-engine/chat — Conversational brand discovery (1 exchange at a time)
app.post("/brand-engine/chat", async (c) => {
  try {
    const user = await requireAuth(c);
    const body = c.get("parsedBody") || await c.req.json().catch(() => ({}));
    const { conversation, vaultContext, exchangeNumber, maxExchanges } = body;

    if (!conversation || !Array.isArray(conversation)) {
      return c.json({ success: false, error: "conversation array required" }, 400);
    }

    const ctx = vaultContext || {};
    const brandInfo = [
      ctx.company_name ? `Marque: ${ctx.company_name}` : "",
      ctx.industry ? `Secteur: ${ctx.industry}` : "",
      ctx.mission ? `Mission: ${ctx.mission}` : "",
      ctx.vision ? `Vision: ${ctx.vision}` : "",
      ctx.personality ? `Personnalité: ${ctx.personality}` : "",
      ctx.usp ? `USP: ${ctx.usp}` : "",
      ctx.tone?.primary_tone ? `Ton: ${ctx.tone.primary_tone}` : "",
    ].filter(Boolean).join("\n");

    const isNearEnd = (exchangeNumber || 1) >= (maxExchanges || 3) - 1;

    const messages = [
      {
        role: "system",
        content: `Tu es un directeur de stratégie de marque senior — 15 ans d'expérience en conseil (Landor, FutureBrand, Dragon Rouge). Tu mènes une conversation de découverte courte et chirurgicale pour extraire l'essence de la marque.

TECHNIQUE DU QUINTUPLE POURQUOI:
Quand le client donne une réponse de surface ("on veut être premium"), creuse avec des "pourquoi" successifs :
- Pourquoi premium ? → "Parce qu'on utilise des matériaux nobles"
- Pourquoi ces matériaux ? → "Parce qu'on croit que la qualité change la vie quotidienne"
→ INSIGHT: La vraie promesse n'est pas "premium" mais "améliorer le quotidien par la qualité"

DÉTECTION DE SIGNAUX BRAND:
Repère ces indices dans les réponses du client :
- Mots récurrents → candidats pour le lexique de marque
- Métaphores spontanées → révèlent l'imaginaire de marque
- Ce qu'ils disent ne PAS vouloir être → définit les frontières du territoire
- Noms de marques citées en référence → triangulation du positionnement
- Contradictions → souvent la source de la tension créative

PRODUCT FIDELITY — RÈGLE ABSOLUE:
- Mentionne UNIQUEMENT les features, ingrédients, specs, prix présents dans le Brand Vault ou le catalogue produit
- N'invente JAMAIS de bénéfices, certifications, récompenses, résultats de tests ou claims de performance
- Si un détail produit n'est pas dans le vault → NE LE MENTIONNE PAS, ne devine pas
- Cite les noms de produits exactement comme ils apparaissent dans le catalogue
- Si un prix est fourni, utilise-le exactement. Sinon, N'INVENTE JAMAIS de prix

BRAND/PRODUCT UNIVERSE COMPLIANCE — OBLIGATOIRE:
- Chaque échange DOIT s'ancrer dans l'univers de communication de la marque (ton, couleurs, codes sémiotiques, direction photo)
- Si un produit spécifique est sélectionné, utilise son UNIVERS PRODUIT (palette, ton, photo_style, keywords) plutôt que les règles génériques de la marque
- Les univers de marque définissent des TERRITOIRES créatifs — inspire-t'en visuellement et verbalement

ANTI-HALLUCINATION — TOLÉRANCE ZÉRO:
- JAMAIS d'invention de certifications, labels ou claims réglementaires (ISO, bio, made in France, etc.) sauf si explicitement dans le vault
- JAMAIS de fabrication de témoignages, citations, histoires clients ou études de cas
- JAMAIS d'invention de statistiques, pourcentages, résultats d'études ou claims comparatifs
- JAMAIS de création de faux prix, classements ou mentions presse
- Si le vault ne le contient pas → la conversation ne le mentionne pas

Contexte de marque déjà connu:
${brandInfo || "Aucune donnée préalable."}

Règles:
- Réponds TOUJOURS en français, avec vouvoiement
- Ton: professionnel mais chaleureux, comme un consultant senior qui écoute vraiment
- Pose UNE SEULE question par message, pas plus
- Chaque question creuse un angle différent: promesse, univers visuel, ce qu'il faut éviter, tension créative, cible émotionnelle
- Si le client donne une réponse de surface → utilise la technique du quintuple pourquoi pour creuser
- Si tu détectes un insight → dis-le : "Ce qui est intéressant c'est que..."
- Ne répète jamais ce que tu sais déjà du scan
- Sois bref: 2-3 phrases max par message
- JAMAIS de platitudes vides ("Merci, c'est noté")
${isNearEnd ? "- C'est le dernier échange. Résume les INSIGHTS clés (pas juste les réponses) et dis que tu vas synthétiser la plateforme de marque. Ajoute readyToSynthesize: true dans ta réponse." : ""}

Retourne UNIQUEMENT du JSON: { "message": "ton message", "readyToSynthesize": false }`
      },
      ...conversation.map((msg: any) => ({
        role: msg.role === "ai" ? "assistant" : "user",
        content: msg.text,
      })),
    ];

    const aiRes = await fetch(`${APIPOD_BASE}/chat/completions`, {
      method: "POST",
      headers: apipodHeaders(),
      body: JSON.stringify({
        model: "gpt-4o",
        temperature: 0.6,
        max_tokens: 300,
        response_format: { type: "json_object" },
        messages,
      }),
    });

    if (!aiRes.ok) {
      return c.json({ success: false, error: "AI chat failed" }, 502);
    }

    const aiData = await aiRes.json();
    const raw = aiData.choices?.[0]?.message?.content || "";
    const parsed = JSON.parse(raw.replace(/```json\s*/g, "").replace(/```\s*/g, "").trim());

    console.log(`[brand-engine/chat] user=${user.id.slice(0, 8)} exchange=${exchangeNumber} ready=${parsed.readyToSynthesize}`);
    return c.json({ success: true, message: parsed.message, readyToSynthesize: !!parsed.readyToSynthesize });
  } catch (err) {
    console.error("[brand-engine/chat] error:", err);
    return c.json({ success: false, error: String(err) }, 500);
  }
});

// POST /brand-engine/synthesize
// Accepts EITHER: { answers: [...], vault } (legacy 5-question format)
// OR: { conversation: [...], vaultContext: {...} } (new chat format)
app.post("/brand-engine/synthesize", async (c) => {
  try {
    const user = await requireAuth(c);
    const body = c.get("parsedBody") || await c.req.json().catch(() => ({}));
    const { answers, vault, conversation, vaultContext } = body;

    // Determine format
    const isConversation = Array.isArray(conversation) && conversation.length > 0;
    const isLegacy = answers && (Array.isArray(answers) ? answers.length >= 5 : Object.keys(answers).length >= 3);

    if (!isConversation && !isLegacy) {
      return c.json({ success: false, error: "conversation or answers required." }, 400);
    }

    // Build brand context
    const ctx = vaultContext || vault || {};
    const brandContext = [
      ctx.company_name || ctx.brandName ? `Marque: ${ctx.company_name || ctx.brandName}` : "",
      ctx.industry ? `Secteur: ${ctx.industry}` : "",
      ctx.tagline ? `Tagline: ${ctx.tagline}` : "",
      ctx.mission ? `Mission: ${ctx.mission}` : "",
      ctx.vision ? `Vision: ${ctx.vision}` : "",
      ctx.personality ? `Personnalité: ${ctx.personality}` : "",
      ctx.usp ? `USP: ${ctx.usp}` : "",
      ctx.tone?.primary_tone ? `Ton: ${ctx.tone.primary_tone} (${(ctx.tone.adjectives || []).join(", ")})` : "",
      (ctx.products_services || []).length > 0 ? `Produits: ${ctx.products_services.join(", ")}` : "",
      (ctx.key_messages || []).length > 0 ? `Messages clés: ${ctx.key_messages.join("; ")}` : "",
      (ctx.approved_terms || []).length > 0 ? `Termes approuvés: ${ctx.approved_terms.join(", ")}` : "",
      (ctx.forbidden_terms || []).length > 0 ? `Termes interdits: ${ctx.forbidden_terms.join(", ")}` : "",
    ].filter(Boolean).join("\n");

    // Build user content
    let userContent: string;
    if (isConversation) {
      const convoText = conversation.map((m: any) => `${m.role === "ai" ? "Consultant" : "Client"}: ${m.text}`).join("\n\n");
      userContent = `Contexte de marque:\n${brandContext}\n\nConversation de découverte:\n${convoText}\n\nSynthétise cette conversation en une plateforme de marque complète.`;
    } else {
      // Legacy format — answers as array or object
      const answerText = Array.isArray(answers)
        ? answers.map((a: string, i: number) => `${i + 1}. ${a}`).join("\n")
        : Object.entries(answers).map(([k, v]) => `${k}: ${v}`).join("\n");
      userContent = `Contexte de marque:\n${brandContext}\n\nRéponses du client:\n${answerText}\n\nSynthétise en une plateforme de marque complète.`;
    }

    const aiRes = await fetch(`${APIPOD_BASE}/chat/completions`, {
      method: "POST",
      headers: apipodHeaders(),
      body: JSON.stringify({
        model: "gpt-4o",
        temperature: 0.4,
        response_format: { type: "json_object" },
        messages: [
          {
            role: "system",
            content: `Tu es un directeur de stratégie de marque senior — 20 ans d'expérience (TBWA, DDB, Publicis, Landor). Tu maîtrises le Prisme de Kapferer, le Golden Circle de Sinek, et la théorie des archétypes de Jung. Tu synthétises les insights en une plateforme de marque structurée et actionnable.

MÉTHODOLOGIE — PRISME DE KAPFERER AUGMENTÉ:
Tu analyses la marque à travers 6 facettes :
1. PHYSIQUE: Les éléments tangibles, visuels, sensoriels — ce qu'on VOIT (logo, couleurs, packaging, produit)
2. PERSONNALITÉ: Si la marque était une personne — traits de caractère, archétype (Creator, Hero, Sage, Explorer, Caregiver, Rebel, Lover, Jester, Ruler, Magician, Innocent, Everyman)
3. CULTURE: Les valeurs profondes et la vision du monde qui inspirent la marque
4. RELATION: Le type de lien que la marque crée avec son public (mentor, complice, guide, provocateur)
5. REFLET: L'image idéalisée du client dans la communication de la marque
6. MENTALISATION: Ce que le client ressent intérieurement en utilisant la marque

TRIANGULATION DE LA PROMESSE:
La promesse de marque est à l'INTERSECTION de 3 cercles :
- Ce que la marque SAIT faire (compétence distinctive)
- Ce que le client DÉSIRE profondément (insight consommateur)
- Ce que les concurrents NE FONT PAS (espace libre)
→ La promesse doit tenir en 1 phrase et être impossible à copier.

FORMULE TENSION CRÉATIVE:
"Nous croyons que [valeur fondamentale] dans un monde où [tension sociétale/culturelle]"
→ La tension crée le récit. Sans tension, pas d'histoire. Exemples :
- "Nous croyons en la lenteur dans un monde obsédé par la vitesse" (luxe artisanal)
- "Nous croyons que tout le monde mérite le premium dans un monde élitiste" (démocratisation)

REGISTRES NARRATIFS (définitions précises):
- transformation: La marque accompagne un AVANT/APRÈS. Le client change grâce à elle. (Nike, Apple)
- connivence: La marque est un allié qui comprend et partage. Ton complice, clin d'œil, humour. (Innocent, Oasis)
- tension: La marque provoque, défie, bouscule les conventions. Ton affirmé, disruptif. (Diesel, Patagonia)
- proof: La marque prouve par les faits, la science, l'expertise. Ton autoritaire, data. (Dyson, The Ordinary)
- culture: La marque incarne un mouvement culturel. Ton communautaire, identitaire. (Supreme, Glossier)

CODES SÉMIOTIQUES:
- adopt: Signes que la marque DOIT utiliser pour être reconnue (cohérence)
- avoid: Signes qui dilueraient l'identité ou copieraient les concurrents (différenciation)
- subvert: Codes de la catégorie à RÉAPPROPRIER de manière inattendue (disruption)

PRODUCT FIDELITY — ABSOLUTE RULE:
- Base la plateforme UNIQUEMENT sur les informations fournies par le client
- JAMAIS d'invention de features, certifications, ou claims produit
- Si une information manque, laisse le champ vide plutôt que d'inventer

ANTI-HALLUCINATION — ZERO TOLERANCE:
- JAMAIS de fabrication de statistiques, études, ou données marché
- JAMAIS d'invention de témoignages, citations, ou cas clients
- JAMAIS de création de faux awards, classements, ou mentions presse
- En cas de doute, utilise un langage aspirationnel ("conçu pour...", "pensé pour...") pas de claims factuels

Retourne UNIQUEMENT du JSON valide:
{
  "promise": "string — la promesse de marque (intersection: compétence × désir × espace libre)",
  "archetype": "string — l'archétype de Jung dominant (et secondaire si pertinent)",
  "narrative_register": "transformation | connivence | tension | proof | culture",
  "creative_tension": "string — formule: Nous croyons que [valeur] dans un monde où [tension]",
  "brand_personality": "string — 4-6 traits de personnalité avec intensité (ex: audacieux 9/10, chaleureux 7/10)",
  "semiotic_codes": {
    "adopt": ["5-8 signes visuels/verbaux à adopter — être CONCRET (pas 'modernité' mais 'lignes épurées, géométrie, espaces blancs')"],
    "avoid": ["5-8 choses à ne jamais montrer/dire — être SPÉCIFIQUE"],
    "subvert": ["2-3 codes de catégorie à réapproprier de manière inattendue"]
  },
  "photo_direction": {
    "framing": "string — types de cadrage préférés (ex: close-up texture, plan large lifestyle, portrait 3/4)",
    "lighting": "string — style d'éclairage (ex: lumière naturelle golden hour, studio minimal, clair-obscur)",
    "human_presence": "string — comment les personnes apparaissent (ex: mains en action, silhouettes, regards caméra)",
    "composition": "string — règles (ex: rule of thirds, negative space 40%, lignes diagonales)"
  },
  "reference_prompts": {
    "positive": ["3-5 prompts de génération d'image alignés avec la marque — DÉTAILLÉS"],
    "negative": ["3-5 anti-prompts — ce que la marque ne doit JAMAIS ressembler à"]
  }
}

RÉPONDS DANS LA MÊME LANGUE que le client.`
          },
          { role: "user", content: userContent }
        ]
      })
    });

    if (!aiRes.ok) {
      const errText = await aiRes.text();
      console.error("[brand-engine/synthesize] AI error:", errText);
      return c.json({ success: false, error: "AI synthesis failed." }, 502);
    }

    const aiData = await aiRes.json();
    const raw = aiData.choices?.[0]?.message?.content || "";
    const cleaned = raw.replace(/```json\s*/g, "").replace(/```\s*/g, "").trim();
    const platform = JSON.parse(cleaned);

    // Save to vault
    const existing = await kv.get(`vault:${user.id}`) || {};
    const updated = { ...existing, brand_platform: platform, updatedAt: new Date().toISOString() };
    await saveVaultToKV(user.id, updated);

    console.log(`[brand-engine/synthesize] user=${user.id.slice(0, 8)} register=${platform.narrative_register} mode=${isConversation ? "chat" : "legacy"}`);
    return c.json({ success: true, platform });
  } catch (err) {
    console.error("[brand-engine/synthesize] error:", err);
    return c.json({ success: false, error: String(err) }, 500);
  }
});

// POST /brand-engine/enrich — Brief-to-Story creative brief engine
// Transforms user prompt into a full creative brief (angle, hook, emotional arc, enriched prompt)
app.post("/brand-engine/enrich", async (c) => {
  try {
    const user = await requireAuth(c);
    const body = c.get("parsedBody") || await c.req.json().catch(() => ({}));
    const { prompt, contentType, brand_platform, territory } = body;

    if (!prompt) return c.json({ success: false, error: "prompt required." }, 400);

    // If no brand platform, return original prompt unchanged
    if (!brand_platform) {
      return c.json({ success: true, enrichedPrompt: prompt, brief: null, wasEnriched: false });
    }

    const bp = brand_platform;
    const contentTypeLabel = contentType || "visual";
    const territoryContext = territory
      ? `\nSELECTED NARRATIVE TERRITORY: "${territory.name}" — ${territory.description}. Angle: ${territory.angle}. Emotional register: ${territory.emotion}.`
      : "";

    const aiRes = await fetch(`${APIPOD_BASE}/chat/completions`, {
      method: "POST",
      headers: apipodHeaders(),
      body: JSON.stringify({
        model: "gpt-4o",
        temperature: 0.4,
        messages: [
          {
            role: "system",
            content: `You are an elite art director and creative director — 15 years at M&C Saatchi, Wieden+Kennedy, 72andSunny. You think in concepts, not executions. Your job is to transform a raw user prompt into a full creative brief, then produce an enriched generation prompt.

METHODOLOGY — INSIGHT-TO-EXECUTION BRIDGE:
1. INSIGHT: What human truth does this content tap into? What does the audience secretly feel/want/fear?
2. CONCEPT: The big idea — a single creative concept that bridges brand promise and audience insight.
3. MOOD: The emotional territory — not just "happy" but specific (nostalgic warmth, quiet confidence, electric anticipation).
4. VISUAL DIRECTION: Concrete staging, composition, and atmosphere instructions that translate the concept into a producible frame.
5. TECHNICAL SPECS: Camera, lighting, color grading, post-production that serve the concept (never decorative).

BRAND PLATFORM:
- Promise: ${bp.promise}
- Narrative register: ${bp.narrative_register}
- Creative tension: ${bp.creative_tension}
- Semiotic codes to ADOPT: ${(bp.semiotic_codes?.adopt || []).join(", ")}
- Semiotic codes to AVOID: ${(bp.semiotic_codes?.avoid || []).join(", ")}
- Semiotic codes to SUBVERT: ${(bp.semiotic_codes?.subvert || []).join(", ")}
- Photo direction: framing=${bp.photo_direction?.framing}, lighting=${bp.photo_direction?.lighting}, human_presence=${bp.photo_direction?.human_presence}, composition=${bp.photo_direction?.composition}
- Positive references: ${(bp.reference_prompts?.positive || []).join(" | ")}
- Negative references (AVOID): ${(bp.reference_prompts?.negative || []).join(" | ")}
${territoryContext}

Content type: ${contentTypeLabel}

TRANSLATION — BRAND PLATFORM → VISUAL DIRECTION:
- Promise → Emotion: What FEELING does this promise create? That feeling IS your visual mood.
- Narrative register → Visual language: transformation=before/after contrast, connivence=intimate/close, tension=bold/dynamic, proof=clean/structured, culture=lifestyle/community
- Semiotic adopt codes → Concrete props/colors/textures in the scene
- Semiotic avoid codes → HARD CONSTRAINTS — if it's in avoid, it MUST NOT appear
- Photo direction → Direct technical instructions for the enriched prompt

FORMAT-SPECIFIC RULES:
- Image: Describe the SCENE (mood, light, composition) not just the subject. Every image tells a micro-story.
- Video: Describe the SEQUENCE (opening shot, rhythm, climax). Movement = emotion.
- Text: Set the VOICE (register, rhythm, hook type). The first 3 words decide if they read the rest.
- Audio: Describe the SONIC TEXTURE (tempo, instruments, mood arc). Sound triggers emotion faster than visuals.

CREATIVE BRIEF RULES:
1. NEVER show the product literally — always communicate the BENEFIT, the TRANSFORMATION, the STORY.
2. Find a creative angle that makes the audience FEEL something before they understand the product.
3. The hook must stop the scroll — surprising, emotional, or thought-provoking.
4. The emotional arc follows: attention → tension → resolution (aligned with brand promise).
5. Visual direction must translate brand codes into concrete staging instructions.
6. Apply the 70/30 rule: 70% brand universe codes, 30% creative surprise (subvert codes).

PRODUCT FIDELITY — ABSOLUTE RULE:
- ONLY reference product features and benefits that are provided in the brief
- NEVER invent product claims, certifications, or performance stats
- If product details are sparse, focus on EMOTION and STORY rather than inventing specs

UNIVERSE COMPLIANCE — MANDATORY:
- Every creation MUST anchor in the brand's semiotic adopt codes
- If semiotic avoid codes exist, they are HARD CONSTRAINTS — never violate them
- Brand photo_direction overrides generic visual choices

ANTI-HALLUCINATION — ZERO TOLERANCE:
- NEVER fabricate product features, testimonials, or data
- NEVER invent awards, press mentions, or endorsements
- When in doubt, use aspirational language ("designed to...", "crafted for...") not factual claims

Return ONLY valid JSON — no markdown, no backticks:
{
  "brief": {
    "angle": "string — the creative angle (1 sentence, what makes this content unique)",
    "hook": "string — the scroll-stopping hook (what grabs attention in 2 seconds)",
    "emotional_arc": "string — attention → tension → resolution in 1-2 sentences",
    "benefit_focus": "string — what the audience gains/feels (NOT what the product does)",
    "visual_direction": "string — concrete staging/mood instructions for the generation",
    "dont": "string — what to explicitly avoid in this specific execution"
  },
  "enrichedPrompt": "string — the final generation prompt incorporating all the above. Concise but rich. For images: describe the scene, mood, lighting, composition. For text: set tone, angle, hook. For video: describe the sequence. For audio: describe the sonic mood."
}`
          },
          {
            role: "user",
            content: `Raw user prompt: "${prompt}"
Content type: ${contentTypeLabel}

Transform this into a creative brief and enriched prompt:`
          }
        ]
      })
    });

    if (!aiRes.ok) {
      console.error("[brand-engine/enrich] AI error:", await aiRes.text());
      return c.json({ success: true, enrichedPrompt: prompt, brief: null, wasEnriched: false });
    }

    const aiData = await aiRes.json();
    const raw = (aiData.choices?.[0]?.message?.content || "").trim();
    try {
      const cleaned = raw.replace(/```json\s*/g, "").replace(/```\s*/g, "").trim();
      const result = JSON.parse(cleaned);
      console.log(`[brand-engine/enrich] user=${user.id.slice(0,8)} type=${contentTypeLabel} angle="${result.brief?.angle?.slice(0,60)}"`);
      return c.json({
        success: true,
        enrichedPrompt: result.enrichedPrompt || prompt,
        brief: result.brief || null,
        wasEnriched: true,
      });
    } catch {
      // Fallback: use raw text as enriched prompt
      console.warn("[brand-engine/enrich] JSON parse failed, using raw text");
      return c.json({ success: true, enrichedPrompt: raw || prompt, brief: null, wasEnriched: true });
    }
  } catch (err) {
    console.error("[brand-engine/enrich] error:", err);
    return c.json({ success: true, enrichedPrompt: prompt, brief: null, wasEnriched: false });
  }
});

// POST /brand-engine/score — Brand alignment scoring for generated content
// Scores how well a generated result aligns with the brand strategy
app.post("/brand-engine/score", async (c) => {
  try {
    const user = await requireAuth(c);
    const body = c.get("parsedBody") || await c.req.json().catch(() => ({}));
    const { prompt, result, contentType, brand_platform } = body;

    if (!brand_platform || !result) {
      return c.json({ success: true, score: null, skipped: true });
    }

    const bp = brand_platform;
    const contentDesc = contentType === "image" || contentType === "film"
      ? `Visual content generated from prompt: "${prompt}". The image/video URL is provided but cannot be analyzed directly — score based on the prompt alignment.`
      : `Text content: "${typeof result === 'string' ? result.slice(0, 1500) : JSON.stringify(result).slice(0, 1500)}"`;

    const aiRes = await fetch(`${APIPOD_BASE}/chat/completions`, {
      method: "POST",
      headers: apipodHeaders(),
      body: JSON.stringify({
        model: "gpt-4o",
        temperature: 0.2,
        messages: [
          {
            role: "system",
            content: `You are a brand compliance guard — senior brand manager with 12 years ensuring brand consistency at L'Oréal, LVMH, and Unilever. You audit EVERY piece of content against the brand platform with zero tolerance for drift.

METHODOLOGY — AUDIT PROTOCOL:
1. READ the generated content carefully
2. COMPARE against each element of the brand platform (promise, register, codes, photo direction)
3. SCORE each criterion with calibrated precision
4. JUSTIFY each score with a specific observation (not vague)
5. RECOMMEND one actionable fix if score < 80

SCORING CALIBRATION — WHAT EACH RANGE MEANS:
- 90-100 ON-BRAND EXEMPLAIRE: Perfect alignment. Could be used as a reference example. Adopt codes present, avoid codes absent, register perfect.
- 75-89 ACCEPTABLE: Minor deviations that don't harm brand perception. Small adjustments would elevate to exemplary.
- 60-74 À RETRAVAILLER: Noticeable drift. Key codes missing or wrong register. Needs revision before publication.
- 40-59 OFF-BRAND: Significant misalignment. Would confuse or dilute brand image. Must be regenerated.
- 0-39 REJECT: Completely wrong territory. Competitors' codes used, or brand damage risk.

BRAND PLATFORM:
- Promise: ${bp.promise}
- Narrative register: ${bp.narrative_register}
- Creative tension: ${bp.creative_tension}
- Codes to ADOPT: ${(bp.semiotic_codes?.adopt || []).join(", ")}
- Codes to AVOID: ${(bp.semiotic_codes?.avoid || []).join(", ")}
- Photo direction: framing=${bp.photo_direction?.framing}, lighting=${bp.photo_direction?.lighting}

SCORING CRITERIA (each 0-100):
1. benefit_vs_product: Does it communicate the BENEFIT/STORY rather than just showing the product? (100 = pure benefit storytelling, 0 = product catalog shot). Weight: 25%.
2. narrative_alignment: Does the tone match the brand's narrative register? Is the vocabulary, rhythm, and emotional texture aligned? Weight: 25%.
3. semiotic_compliance: Does it use adopted codes? Are forbidden codes absent? Check EVERY adopt and avoid code explicitly. Weight: 20%.
4. emotional_impact: Does it provoke the specific emotion aligned with the brand promise? Not just "positive" but the RIGHT emotion. Weight: 15%.
5. scroll_stop: Would this genuinely stop someone scrolling? Is it surprising, beautiful, or thought-provoking in a way that serves the brand? Weight: 15%.

PRODUCT FIDELITY CHECK (separate from scoring):
- Does the content mention ONLY real product features/claims from the vault?
- Are there ANY invented certifications, stats, or testimonials? → Flag immediately
- Are product names exact? Prices correct?

ANTI-HALLUCINATION CHECK:
- Flag any fabricated claims, stats, awards, or testimonials
- Flag any regulatory/legal claims not in the vault (ISO, bio, made in France, etc.)
- If hallucinations detected → overall score capped at 40 regardless of other criteria

Return ONLY valid JSON:
{
  "overall": number (0-100, weighted average per weights above),
  "scores": {
    "benefit_vs_product": number,
    "narrative_alignment": number,
    "semiotic_compliance": number,
    "emotional_impact": number,
    "scroll_stop": number
  },
  "verdict": "on-brand" | "acceptable" | "needs-work" | "off-brand",
  "adopt_codes_found": ["list of adopt codes detected in content"],
  "avoid_codes_found": ["list of avoid codes detected — should be EMPTY for on-brand"],
  "hallucinations_detected": ["list of any fabricated claims found — should be EMPTY"],
  "suggestion": "string — one specific, actionable improvement (not vague: 'Replace X with Y because Z')"
}`
          },
          {
            role: "user",
            content: `Content type: ${contentType}\n${contentDesc}\n\nScore this content:`
          }
        ]
      })
    });

    if (!aiRes.ok) {
      console.error("[brand-engine/score] AI error:", await aiRes.text());
      return c.json({ success: true, score: null, skipped: true });
    }

    const aiData = await aiRes.json();
    const raw = (aiData.choices?.[0]?.message?.content || "").trim();
    const cleaned = raw.replace(/```json\s*/g, "").replace(/```\s*/g, "").trim();
    const score = JSON.parse(cleaned);

    console.log(`[brand-engine/score] user=${user.id.slice(0,8)} overall=${score.overall} verdict=${score.verdict}`);
    return c.json({ success: true, score });
  } catch (err) {
    console.error("[brand-engine/score] error:", err);
    return c.json({ success: true, score: null, skipped: true });
  }
});

// POST /brand-engine/territories — Generate narrative territories from brand vault
// Returns 5-7 pre-validated creative angles the user can pick from
app.post("/brand-engine/territories", async (c) => {
  try {
    const user = await requireAuth(c);
    const body = c.get("parsedBody") || await c.req.json().catch(() => ({}));

    // Load vault to get brand context
    const vault = body.vault || await kv.get(`vault:${user.id}`) || {};
    const bp = vault.brand_platform;

    const brandContext = `Brand: ${vault.brandName || vault.company_name || "Unknown"}
Industry: ${vault.industry || "N/A"}
Tagline: ${vault.tagline || "N/A"}
Products: ${(vault.products_services || []).join(", ") || "N/A"}
Tone: ${vault.tone_of_voice || "N/A"}
Key messages: ${(vault.key_messages || []).join(". ") || "N/A"}`;

    const platformContext = bp
      ? `\nBRAND PLATFORM:
- Promise: ${bp.promise}
- Narrative register: ${bp.narrative_register}
- Creative tension: ${bp.creative_tension}
- Semiotic codes to adopt: ${(bp.semiotic_codes?.adopt || []).join(", ")}
- Semiotic codes to subvert: ${(bp.semiotic_codes?.subvert || []).join(", ")}`
      : "";

    const aiRes = await fetch(`${APIPOD_BASE}/chat/completions`, {
      method: "POST",
      headers: apipodHeaders(),
      body: JSON.stringify({
        model: "gpt-4o",
        temperature: 0.6,
        messages: [
          {
            role: "system",
            content: `You are a senior brand planner. Based on the brand DNA, generate 6 narrative territories — recurring creative angles the brand can use across all content.

Each territory is NOT a single post idea — it's a REUSABLE ANGLE that can generate dozens of contents across formats (image, video, text, sound).

RULES:
- Each territory focuses on BENEFIT/STORY, never on product features
- Territories must be diverse: some emotional, some rational, some subversive
- Names must be evocative and memorable (2-4 words max)
- Each territory should suggest a different emotional register
- Include at least one "subversive" territory that challenges industry conventions
- RESPOND IN THE SAME LANGUAGE as the brand context

Return ONLY valid JSON — no markdown, no backticks:
{
  "territories": [
    {
      "id": "string — kebab-case unique id",
      "name": "string — evocative territory name (2-4 words)",
      "description": "string — what this territory explores (1-2 sentences)",
      "angle": "string — the creative angle to take (1 sentence)",
      "emotion": "string — the primary emotion this territory triggers",
      "example_prompts": ["string — 3 example prompts using this territory"],
      "best_for": ["image", "text", "film", "sound"]
    }
  ]
}`
          },
          {
            role: "user",
            content: `${brandContext}${platformContext}

Generate 6 narrative territories for this brand:`
          }
        ]
      })
    });

    if (!aiRes.ok) {
      console.error("[brand-engine/territories] AI error:", await aiRes.text());
      return c.json({ success: false, error: "AI generation failed." }, 502);
    }

    const aiData = await aiRes.json();
    const raw = (aiData.choices?.[0]?.message?.content || "").trim();
    const cleaned = raw.replace(/```json\s*/g, "").replace(/```\s*/g, "").trim();
    const result = JSON.parse(cleaned);

    // Cache territories in vault
    const existing = await kv.get(`vault:${user.id}`) || {};
    const updated = { ...existing, narrative_territories: result.territories, territories_updatedAt: new Date().toISOString() };
    await saveVaultToKV(user.id, updated);

    console.log(`[brand-engine/territories] user=${user.id.slice(0,8)} count=${result.territories?.length}`);
    return c.json({ success: true, territories: result.territories });
  } catch (err) {
    console.error("[brand-engine/territories] error:", err);
    return c.json({ success: false, error: String(err) }, 500);
  }
});

